  ('disabled-6e2f88c7-moex-00067', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '下列何者應依申訴、再申訴程序提起救濟？', '["長官對於其屬官所為申誡以上之懲處", "行政機關組成性騷擾處理委員會所作成性騷擾成立之決定", "行政機關對於退休公務人員停發三節慰問金", "長官所編定之值班表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
