  ('disabled-6e2f88c7-moex-00073', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '有關行政契約之敘述，下列何者正確？', '["行政契約締結之形式，得以口頭或書面的方式為之", "行政契約當事人之一方為人民，若行政機關為防止或除去對公益之重大 危害而終止契約時，基於公益之維護，毋庸補償人民財產上之損失", "行政契約內容侵害第三人權利時，應經第三人書面同意，始生效力", "基於契約自由原則，所有公法上法律關係皆得以行政契約之形式加以規 範，毋須考慮法規之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00074', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '下列何者為行政事實行為？', '["公園開放使用之公告", "地政機關所為土地移轉登記", "函請受領人繳還因撤銷補貼許可所生溢領金額之通知", "文化部函復內政部移民署某甲不符入境許可條件之通知"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00075', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '下列何者非行政罰？', '["甲為證券商之總經理，因違反證券交易法，遭主管機關解除其經理人職務", "乙因違反道路交通管理處罰條例，遭主管機關處以罰鍰", "丙無正當理由，攜帶具殺傷力之器械，因違反社會秩序維護法，遭主管 機關沒入其器械", "丁為學校教師，因體罰學生，違反兒童及少年福利與權益保障法規定， 遭主管機關公布其姓名 30830"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00076', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-3082b5f1', 'sub-disabled-6e2f88c7-02', NULL, 'single_choice', '關於行政執行聲明異議之敘述，下列何者錯誤？', '["對具行政處分性質之執行命令不服，經依行政執行法之聲明異議程序， 聲明異議人可直接提起撤銷訴訟", "受理機關認為聲明異議無理由者，應予以駁回", "不服中央各院之行政執行而聲明異議，由中央各院自行受理異議並為 決定", "受理機關認為聲明異議有理由者，應即停止執行，並撤銷或更正已為之 執行行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL)
